/*
 * waitfg - Block until process pid is no longer the foreground process.
 *
 * Requires:
 *   "pid" is the PID of the current foreground job.
 *
 * Effects:
 *   Blocks SIGCHLD before entering the loop to eliminate the race
 *   condition between the fgpid check and sigsuspend. sigsuspend
 *   atomically unblocks SIGCHLD and waits, preventing missed signals.
 */
static void
waitfg(pid_t pid)
{
	sigset_t mask, prev;

	// Block SIGCHLD to close the race between fgpid check and sigsuspend.
	sigemptyset(&mask);
	sigaddset(&mask, SIGCHLD);
	sigprocmask(SIG_BLOCK, &mask, &prev);

	// sigsuspend(&prev) atomically restores prev (SIGCHLD unblocked)
	// and suspends, so any pending SIGCHLD is delivered before sleeping.
	while (fgpid(jobs) == pid)
		sigsuspend(&prev);

	// Restore previous signal mask (SIGCHLD unblocked).
	sigprocmask(SIG_SETMASK, &prev, NULL);
}

