/*
 * kill_all_jobs - Send SIGKILL to all remaining job process groups.
 *
 * Requires:
 *   Nothing.
 *
 * Effects:
 *   Blocks SIGCHLD to suppress termination messages, then sends SIGKILL
 *   to every active job's process group. This ensures orphaned stopped
 *   or background jobs release their file descriptors (such as the
 *   stdout pipe to the test driver) when the shell exits.
 */
static void
kill_all_jobs(void)
{
	sigset_t mask;
	int i;

	// Block SIGCHLD so sigchld_handler won't print termination messages.
	sigemptyset(&mask);
	sigaddset(&mask, SIGCHLD);
	sigprocmask(SIG_BLOCK, &mask, NULL);

	for (i = 0; i < MAXJOBS; i++) {
		if (jobs[i].pid > 0)
			kill(-(int)jobs[i].pid, SIGKILL);
	}
}

